import * as THREE from 'three';
import { OrbitControls } from 'three/addons/controls/OrbitControls.js';
import { FBXLoader } from 'three/addons/loaders/FBXLoader.js';

const vpEl = document.getElementById('vp');
const setStatus = t => document.getElementById('statusTxt').textContent = t;

// ── Three ──
const scene = new THREE.Scene();
scene.background = new THREE.Color(0x1e2028);
const camera = new THREE.PerspectiveCamera(50,1,0.01,5000);
camera.position.set(2,2,3);
const renderer = new THREE.WebGLRenderer({antialias:true});
renderer.setPixelRatio(devicePixelRatio);
vpEl.appendChild(renderer.domElement);
const controls = new OrbitControls(camera,renderer.domElement);
controls.enableDamping=true; controls.dampingFactor=0.08;
scene.add(new THREE.AmbientLight(0xffffff,0.7));
const dl=new THREE.DirectionalLight(0xffffff,1.1); dl.position.set(3,5,4); scene.add(dl);
const dl2=new THREE.DirectionalLight(0x8899ff,0.4); dl2.position.set(-4,-2,-3); scene.add(dl2);
scene.add(new THREE.GridHelper(10,20,0x25272f,0x1c1f27));
function resize(){const w=vpEl.clientWidth,h=vpEl.clientHeight;renderer.setSize(w,h);camera.aspect=w/h;camera.updateProjectionMatrix();}
resize();
(function loop(){requestAnimationFrame(loop);controls.update();renderer.render(scene,camera);})();
document.getElementById('bgColor').addEventListener('input',e=>{scene.background=new THREE.Color(e.target.value);});

window.addEventListener('resize', () => resize());


// ── Texture state ──
const TEX=2048;
let model=null,modelRadius=1,uvFlipped=false,dynTex=null;
const mk=()=>Object.assign(document.createElement('canvas'),{width:TEX,height:TEX});
const baseC=mk(),compC=mk();
const baseX=baseC.getContext('2d'),compX=compC.getContext('2d');
baseX.fillStyle='#9a9a9a'; baseX.fillRect(0,0,TEX,TEX);

// ── Masks ──
// default mask = full white (no masking)
const BUILTIN_MASK_B64 = 'data:image/png;base64,';
const defaultMask = {id:0, name:'None (full)', img:null, thumb:null};
const builtinMaskImg = new Image();
builtinMaskImg.onload = () => {
  const th=Object.assign(document.createElement('canvas'),{width:32,height:32});
  th.getContext('2d').drawImage(builtinMaskImg,0,0,32,32);
  masks.push({id:1, name:'mask1 (built-in)', img:builtinMaskImg, thumb:th.toDataURL()});
  renderMasks();
};
builtinMaskImg.src = BUILTIN_MASK_B64;
const masks = [defaultMask]; // index 0 = no mask
let _selMaskForPal = {}; // palIdx -> maskIdx in masks[]

function createWhiteCanvas(w,h){
  const c=Object.assign(document.createElement('canvas'),{width:w,height:h});
  c.getContext('2d').fillStyle='#fff'; c.getContext('2d').fillRect(0,0,w,h);
  return c;
}

// ── Palette ──
const palette=[]; let activePal=-1;
// ── Layers ──
const layers=[]; let selLayer=-1; let seq=0;
const undoStack=[],redoStack=[];

function pushUndo(a){undoStack.push(a);if(undoStack.length>40)undoStack.shift();redoStack.length=0;refreshHist();}
function refreshHist(){
  document.getElementById('undoBtn').disabled=!undoStack.length;
  document.getElementById('redoBtn').disabled=!redoStack.length;
}

function recomp(){
  // Start with solid grey (no base layer — everything is in layer stack)
  compX.clearRect(0,0,TEX,TEX);
  compX.fillStyle='#9a9a9a';
  compX.fillRect(0,0,TEX,TEX);
  for(const L of layers){
    if(!L.visible) continue;
    const adj=mk();
    const ax=adj.getContext('2d');
    ax.filter=`brightness(${L.brightness}%) contrast(${L.contrast}%)`;
    ax.globalAlpha=L.opacity/100;
    ax.drawImage(L.canvas,0,0);
    compX.drawImage(adj,0,0);
  }
  if(dynTex) dynTex.needsUpdate=true;
}

function initTex(){
  dynTex=new THREE.CanvasTexture(compC);
  dynTex.colorSpace=THREE.SRGBColorSpace;
  dynTex.flipY=uvFlipped;
  recomp();
}

// ── FBX ──
document.getElementById('fbxIn').addEventListener('change',e=>{
  const f=e.target.files[0]; if(!f) return;
  setStatus('Loading FBX...');
  const url=URL.createObjectURL(f);
  new FBXLoader().load(url,obj=>{
    if(model) scene.remove(model);
    model=obj;
    const box=new THREE.Box3().setFromObject(obj);
    const sz=box.getSize(new THREE.Vector3());
    const ctr=box.getCenter(new THREE.Vector3());
    const md=Math.max(sz.x,sz.y,sz.z)||1, sc=2.5/md;
    obj.scale.setScalar(sc); obj.position.sub(ctr.multiplyScalar(sc));
    obj.updateMatrixWorld(true); modelRadius=md*sc/2;
    let nativeTex=null;
    obj.traverse(ch=>{
      if(!ch.isMesh) return;
      const m=Array.isArray(ch.material)?ch.material[0]:ch.material;
      if(m&&m.map&&m.map.image&&!nativeTex) nativeTex=m.map;
    });
    if(nativeTex&&nativeTex.image){
      uvFlipped=true;
      // Create a layer from the native texture
      const lc=mk();
      lc.getContext('2d').drawImage(nativeTex.image,0,0,TEX,TEX);
      const th=Object.assign(document.createElement('canvas'),{width:48,height:48});
      th.getContext('2d').drawImage(lc,0,0,48,48);
      layers.push({id:++seq,name:'Layer 1 (texture)',canvas:lc,thumb:th.toDataURL(),
                   visible:true,open:false,opacity:100,brightness:100,contrast:100});
      selLayer=0;
    } else {
      uvFlipped=false;
    }
    layers.length=0;selLayer=-1;undoStack.length=0;redoStack.length=0;refreshHist();
    initTex();
    obj.traverse(ch=>{if(ch.isMesh)ch.material=new THREE.MeshStandardMaterial({map:dynTex,roughness:.85,metalness:.05});});
    scene.add(obj);
    const nb=new THREE.Box3().setFromObject(obj);
    const c2=nb.getCenter(new THREE.Vector3());
    controls.target.copy(c2);
    camera.position.set(c2.x+2.5,c2.y+1.8,c2.z+3); controls.update();
    document.getElementById('flipBtn').disabled=false;
    document.getElementById('exportBtn').disabled=false;
    renderLayers();
    setStatus('Model loaded — select a decal and click on the model');
    URL.revokeObjectURL(url);
  },undefined,err=>{setStatus('FBX load error');console.error(err);});
});

document.getElementById('flipBtn').addEventListener('click',()=>{
  if(!dynTex) return;
  uvFlipped=!uvFlipped;dynTex.flipY=uvFlipped;dynTex.needsUpdate=true;
  setStatus('UV flip: '+uvFlipped);
});

// ── Masks panel collapse ──
let masksCollapsed = false;
document.getElementById('masksHead').addEventListener('click', e => {
  if(e.target.id === 'addMaskBtn') return; // don't collapse when clicking +
  masksCollapsed = !masksCollapsed;
  document.getElementById('masksList').style.display = masksCollapsed ? 'none' : '';
  document.getElementById('masksArrow').style.transform = masksCollapsed ? 'rotate(-90deg)' : '';
});

// ── Masks loading ──
document.getElementById('addMaskBtn').addEventListener('click',()=>document.getElementById('maskIn').click());
document.getElementById('maskIn').addEventListener('change',e=>{
  const f=e.target.files[0]; if(!f) return;
  const img=new Image();
  img.onload=()=>{
    const th=Object.assign(document.createElement('canvas'),{width:32,height:32});
    th.getContext('2d').drawImage(img,0,0,32,32);
    masks.push({id:masks.length,name:f.name,img,thumb:th.toDataURL()});
    renderMasks();
    setStatus('Mask loaded: '+f.name);
  };
  const objUrl=URL.createObjectURL(f);
  e.target.value='';
  img.src=objUrl;
});

function syncSessionMasks(){
  // Remove old session-flagged masks
  for(let i=masks.length-1;i>=0;i--) if(masks[i].fromSession) masks.splice(i,1);
  // Add current session masks
  if(window.SessionStore){
    for(const sm of window.SessionStore.sessionMasks){
      masks.push({id:'sess_'+sm.id, name:sm.name+' (session)', img:sm.img, thumb:sm.thumb, fromSession:true});
    }
  }
}

function renderMasks(){
  syncSessionMasks();
  const el=document.getElementById('masksList');
  el.innerHTML='';
  masks.forEach((m,i)=>{
    if(i===0) return; // "None" shown inline in palette dropdown
    const row=document.createElement('div'); row.className='mcard';
    row.innerHTML=`<img src="${m.thumb}" style="filter:grayscale(1)"><span class="mn">${m.name}</span>`;
    el.appendChild(row);
  });
  if(masks.length<=1) el.innerHTML='<div class="empty">no masks</div>';
  renderPalMaskDropdowns();
}

// Listen for session changes
if(window.SessionStore) window.SessionStore.onChange(() => renderMasks());

// ── Palette ──
const palEl=document.getElementById('palette');
document.getElementById('decalIn').addEventListener('change',e=>{
  const f=e.target.files[0]; if(!f) return;
  const img=new Image();
  img.onload=()=>{
    const idx=palette.length;
    _selMaskForPal[idx]=0; // default: no mask
    const el=document.createElement('div'); el.className='pi';
    el.dataset.idx=idx;
    el.innerHTML=`
      <div class="pi-top">
        <img src="${img.src}">
        <span class="pname">${f.name}</span>
        <span class="parr">▶</span>
      </div>
      <div class="pi-sub">
        <div class="mask-sel">Mask:</div>
        <div class="mask-grid" data-pidx="${idx}"></div>
      </div>`;
    el.querySelector('.pi-top').addEventListener('click',ev=>{
      if(ev.target.classList.contains('parr')){
        el.classList.toggle('open'); return;
      }
      activePal=idx; renderPal(); setStatus('Decal selected — click on the model');
      refreshDecalPreview();
    });
    palEl.querySelector('.empty')?.remove();
    palEl.appendChild(el);
    palette.push({name:f.name,img,el});
    activePal=idx; renderPal();
    populateMaskGrid(idx);
    refreshDecalPreview();
  };
  img.src=URL.createObjectURL(f);
});

function renderPal(){[...palEl.querySelectorAll('.pi')].forEach(el=>el.classList.toggle('active',+el.dataset.idx===activePal));}
function renderPalMaskDropdowns(){palette.forEach((_,i)=>populateMaskGrid(i));}

function populateMaskGrid(pidx){
  const grid=palEl.querySelector(`.mask-grid[data-pidx="${pidx}"]`); if(!grid) return;
  grid.innerHTML='';
  masks.forEach((m,mi)=>{
    const row=document.createElement('div'); row.className='mi'+(_selMaskForPal[pidx]===mi?' sel':'');
    if(m.img) row.innerHTML=`<img src="${m.thumb}" style="filter:grayscale(1)"><span class="mname">${m.name}</span>`;
    else row.innerHTML=`<span class="mname" style="padding-left:2px">None (full)</span>`;
    row.addEventListener('click',e=>{e.stopPropagation();_selMaskForPal[pidx]=mi;populateMaskGrid(pidx);refreshDecalPreview();});
    grid.appendChild(row);
  });
}

// ── Sliders sync ──
const sEl=document.getElementById('size'),rEl=document.getElementById('rot');
const sV=document.getElementById('szVal'),rV=document.getElementById('rotVal');
function syncSlider(range,num,mn,mx){
  range.addEventListener('input',()=>{num.value=range.value;});
  num.addEventListener('input',()=>{let v=Math.round(Math.min(mx,Math.max(mn,+num.value||mn)));num.value=v;range.value=v;});
  num.addEventListener('blur',()=>{let v=Math.round(Math.min(mx,Math.max(mn,+num.value||mn)));num.value=v;range.value=v;});
}
syncSlider(sEl,sV,0,100); syncSlider(rEl,rV,0,360);

// ── Layers render ──
const listEl=document.getElementById('layersList');
function renderLayers(){
  listEl.innerHTML='';
  if(!layers.length){
    listEl.innerHTML='<div class="empty">no layers — use + or 🖼 to add one</div>';
    return;
  }

  document.getElementById('dupLayerBtn').style.display = (selLayer>=0&&selLayer<layers.length) ? 'inline' : 'none';

  // Show layers top-to-bottom (last = bottom)
  layers.slice().reverse().forEach(L=>{
    const ri=layers.indexOf(L);
    const card=document.createElement('div');
    card.className='lc'+(L.visible?'':' hid')+(ri===selLayer?' sel':'')+(L.open?' open':'');

    card.innerHTML=`
      <div class="lc-top">
        <img src="${L.thumb}">
        <span class="lname">${L.name}</span>
        <span class="lc-ic chk" title="expand" style="font-size:18px;padding:0 5px">▾</span>
        <span class="lc-ic eye">${L.visible?'👁':'—'}</span>
        <span class="lc-ic del">🗑</span>
      </div>
      <div class="lc-exp">
        <div class="srow">
          <label>Opacity</label>
          <input type="range" min="0" max="100" step="1" value="${L.opacity}" class="layr" data-prop="opacity">
          <input type="number" class="nv layn" min="0" max="100" step="1" value="${L.opacity}" data-prop="opacity">
        </div>
        <div class="srow">
          <label>Bright</label>
          <input type="range" min="0" max="200" step="1" value="${L.brightness}" class="layr" data-prop="brightness">
          <input type="number" class="nv layn" min="0" max="200" step="1" value="${L.brightness}" data-prop="brightness">
        </div>
        <div class="srow">
          <label>Contrast</label>
          <input type="range" min="0" max="200" step="1" value="${L.contrast}" class="layr" data-prop="contrast">
          <input type="number" class="nv layn" min="0" max="200" step="1" value="${L.contrast}" data-prop="contrast">
        </div>
      </div>`;

    card.querySelector('.lname').onclick=()=>{selLayer=ri;renderLayers();};
    card.querySelector('.chk').onclick=()=>{L.open=!L.open;renderLayers();};
    card.querySelector('.eye').onclick=()=>{L.visible=!L.visible;recomp();renderLayers();pushUndo({type:'vis',id:L.id});};
    card.querySelector('.del').onclick=()=>{
      const pos=layers.indexOf(L),rem=layers.splice(pos,1)[0];
      if(selLayer===pos)selLayer=-1;
      else if(selLayer>pos)selLayer--;
      recomp();renderLayers();pushUndo({type:'del',layer:rem,pos});
    };
    card.querySelectorAll('.layr').forEach(r=>{
      r.addEventListener('input',()=>{
        L[r.dataset.prop]=+r.value;
        card.querySelector(`.layn[data-prop="${r.dataset.prop}"]`).value=r.value;
        recomp();
      });
    });
    card.querySelectorAll('.layn').forEach(n=>{
      n.addEventListener('input',()=>{
        const prop=n.dataset.prop;
        const cfg={opacity:[0,100],brightness:[0,200],contrast:[0,200]};
        const [mn,mx]=cfg[prop];
        let v=Math.round(Math.min(mx,Math.max(mn,+n.value||mn)));
        n.value=v; L[prop]=v;
        card.querySelector(`.layr[data-prop="${prop}"]`).value=v;
        recomp();
      });
    });
    listEl.appendChild(card);
  });
}

// ── Raycast ──
// ── Tool state ──
let activeTool = 'decal';
let stampSrc = null;
let stampOffset = null;

document.querySelectorAll('.tool-btn').forEach(btn => {
  btn.addEventListener('click', () => {
    activeTool = btn.dataset.tool;
    document.querySelectorAll('.tool-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
    document.getElementById('stampHint').style.display = activeTool === 'stamp' ? 'block' : 'none';
    stampSrc = null; stampOffset = null;
    hideCursors();
    controls.enabled = true;
    setStatus(activeTool === 'blur'  ? 'Blur: drag on model surface' :
              activeTool === 'stamp' ? 'Stamp: Ctrl+Click to set source, then drag to paint' :
              'Decal: select decal and click on model');
    refreshDecalPreview();
  });
});

// sync strength slider
const stEl = document.getElementById('strength'), stV = document.getElementById('stVal');
syncSlider(stEl, stV, 1, 20);

// ── Cursor overlays ──

// 1) Circle cursor — for blur / stamp tools
const cursorCircle = document.createElement('div');
cursorCircle.style.cssText = `
  position:fixed;pointer-events:none;border-radius:50%;
  border:1.5px solid rgba(255,255,255,0.75);display:none;
  transform:translate(-50%,-50%);z-index:9999;
  box-shadow:0 0 0 1px rgba(0,0,0,0.5);
`;
document.body.appendChild(cursorCircle);

// 2) Decal preview — canvas that follows cursor for decal tool
const decalPreviewCanvas = document.createElement('canvas');
decalPreviewCanvas.style.cssText = `
  position:fixed;pointer-events:none;display:none;
  transform:translate(-50%,-50%);z-index:9999;
  image-rendering:pixelated;
`;
document.body.appendChild(decalPreviewCanvas);
const dpCtx = decalPreviewCanvas.getContext('2d');

// Build the decal preview image (decal + mask applied at 0.5 alpha)
function buildDecalPreview() {
  const d = palette[activePal];
  if(!d || activeTool !== 'decal') return;
  const img = d.img;
  const maskDef = masks[_selMaskForPal[activePal] || 0];

  // offscreen: apply mask to decal
  const oc = Object.assign(document.createElement('canvas'), {width: img.width, height: img.height});
  const ox = oc.getContext('2d');
  ox.drawImage(img, 0, 0);

  if(maskDef && maskDef.img) {
    const mc = Object.assign(document.createElement('canvas'), {width: img.width, height: img.height});
    const mx = mc.getContext('2d');
    mx.drawImage(maskDef.img, 0, 0, img.width, img.height);
    const md = mx.getImageData(0, 0, img.width, img.height);
    const id = ox.getImageData(0, 0, img.width, img.height);
    for(let i = 0; i < id.data.length; i += 4)
      id.data[i+3] = Math.round(id.data[i+3] * (md.data[i]/255));
    ox.putImageData(id, 0, 0);
  }

  // rotation
  const rot = (+rEl.value) * Math.PI / 180;
  const aspect = img.width / img.height;

  // Compute screen size matching actual world-space decal size
  // worldSize = (size/100) * modelRadius*2, same formula as projectDecal
  const worldSize = (+sEl.value / 100) * (modelRadius * 2);
  const worldW = worldSize * (aspect >= 1 ? 1 : aspect);
  const worldH = worldSize * (aspect >= 1 ? 1/aspect : 1);

  // Project a world-space length to screen pixels at distance from camera
  // Use a point slightly in front of the model center to estimate scale
  const camDist = camera.position.distanceTo(controls.target);
  const fovRad = camera.fov * Math.PI / 180;
  const screenH = renderer.domElement.clientHeight;
  const pxPerUnit = (screenH / 2) / (Math.tan(fovRad/2) * camDist);

  const baseW = Math.max(8, Math.round(worldW * pxPerUnit * 1.1));
  const baseH = Math.max(4, Math.round(worldH * pxPerUnit * 1.1));

  // canvas must contain rotated rect without clipping
  const diag = Math.ceil(Math.sqrt(baseW*baseW + baseH*baseH));
  decalPreviewCanvas.width  = diag;
  decalPreviewCanvas.height = diag;
  dpCtx.clearRect(0, 0, diag, diag);
  dpCtx.save();
  dpCtx.translate(diag/2, diag/2);
  dpCtx.rotate(rot);
  dpCtx.globalAlpha = 0.55;
  dpCtx.drawImage(oc, -baseW/2, -baseH/2, baseW, baseH);
  // border — drawn inside the rotate transform so it wraps the image exactly
  dpCtx.globalAlpha = 1;
  dpCtx.strokeStyle = 'rgba(255,255,255,0.85)';
  dpCtx.lineWidth = 1.5;
  dpCtx.strokeRect(-baseW/2, -baseH/2, baseW, baseH);
  dpCtx.restore();

  decalPreviewCanvas.style.width  = diag + 'px';
  decalPreviewCanvas.style.height = diag + 'px';
}

function updateCursorPos(e) {
  const x = e.clientX, y = e.clientY;

  if(activeTool === 'blur' || activeTool === 'stamp') {
    decalPreviewCanvas.style.display = 'none';
    cursorCircle.style.display = 'block';
    const r = getCursorRadius();
    cursorCircle.style.left = x + 'px';
    cursorCircle.style.top  = y + 'px';
    cursorCircle.style.width  = r*2 + 'px';
    cursorCircle.style.height = r*2 + 'px';
  } else if(activeTool === 'decal' && activePal >= 0) {
    cursorCircle.style.display = 'none';
    decalPreviewCanvas.style.display = 'block';
    buildDecalPreview();
    decalPreviewCanvas.style.left = x + 'px';
    decalPreviewCanvas.style.top  = y + 'px';
  } else {
    cursorCircle.style.display = 'none';
    decalPreviewCanvas.style.display = 'none';
  }
}

function hideCursors() {
  cursorCircle.style.display = 'none';
  decalPreviewCanvas.style.display = 'none';
}

renderer.domElement.addEventListener('mousemove', updateCursorPos);
renderer.domElement.addEventListener('mouseleave', hideCursors);

// Rebuild preview when relevant settings change
function refreshDecalPreview() { if(activeTool==='decal' && activePal>=0) buildDecalPreview(); }
sEl.addEventListener('input', () => {
  getCursorRadius(); // keep circle in sync
  refreshDecalPreview();
});
rEl.addEventListener('input', refreshDecalPreview);
// (opacity is per-layer now, no global oEl)

function getCursorRadius() {
  return Math.max(4, Math.round((+sEl.value / 100) * 80));
}

// ── Ray helpers ──
const ray = new THREE.Raycaster(), mouse = new THREE.Vector2();

function getHit(e) {
  const rc = renderer.domElement.getBoundingClientRect();
  mouse.x = ((e.clientX - rc.left) / rc.width) * 2 - 1;
  mouse.y = -((e.clientY - rc.top) / rc.height) * 2 + 1;
  ray.setFromCamera(mouse, camera);
  const hits = ray.intersectObject(model, true);
  return hits.length ? hits[0] : null;
}

// ── Pointer events ──
let isPainting = false;
let drag = false;

renderer.domElement.addEventListener('pointerdown', e => {
  drag = false;
  if(!model) return;
  if(e.altKey) { controls.enabled = true; return; }
  if(activeTool === 'blur' || activeTool === 'stamp') {
    controls.enabled = false;
    isPainting = true;
    handlePaint(e);
  } else {
    controls.enabled = true;
  }
});

renderer.domElement.addEventListener('pointermove', e => {
  drag = true;
  if(!model || !isPainting) return;
  if(activeTool === 'blur' || activeTool === 'stamp') handlePaint(e);
});

renderer.domElement.addEventListener('pointerup', e => {
  if(isPainting) { isPainting = false; controls.enabled = true; return; }
  if(drag || activeTool !== 'decal' || !model || activePal < 0) return;
  const rc = renderer.domElement.getBoundingClientRect();
  mouse.x = ((e.clientX - rc.left) / rc.width) * 2 - 1;
  mouse.y = -((e.clientY - rc.top) / rc.height) * 2 + 1;
  ray.setFromCamera(mouse, camera);
  const hits = ray.intersectObject(model, true);
  if(!hits.length){ setStatus('Missed — click on the model surface'); return; }
  projectDecal(hits[0]);
});

window.addEventListener('keydown', e => { if(e.key === 'Alt' && !isPainting) controls.enabled = true; });

function handlePaint(e) {
  const isCtrl = e.ctrlKey || e.metaKey;
  const rc = renderer.domElement.getBoundingClientRect();
  const sx = e.clientX - rc.left, sy = e.clientY - rc.top;

  if(activeTool === 'stamp' && isCtrl) {
    // Photoshop-style: remember the SCREEN point of the source
    const hit = getHit(e); if(!hit) { setStatus('Stamp: click on the model to set source'); return; }
    stampSrc = {sx, sy};        // screen coords of source
    stampOffset = null;          // will be set on first paint stroke
    cursorCircle.style.borderColor = 'rgba(60,220,180,0.9)';
    setStatus('Stamp source set — now drag to paint');
    return;
  }

  cursorCircle.style.borderColor = 'rgba(255,255,255,0.75)';

  if(activeTool === 'blur') {
    const hit = getHit(e); if(!hit) return;
    applyWorldBrush(hit, 'blur', null);
  } else if(activeTool === 'stamp') {
    if(!stampSrc) { setStatus('Stamp: Ctrl+Click to set source first'); return; }
    // On the first paint, lock the screen-space offset (dest - source)
    if(!stampOffset) stampOffset = {dx: sx - stampSrc.sx, dy: sy - stampSrc.sy};
    applyScreenStamp(sx, sy, rc);
  }
}

// ── Screen-space clone stamp (Photoshop-style) ──
// For each screen pixel inside the brush, raycast it AND its source-offset
// counterpart into the model, then copy color from source UV → dest UV.
function applyScreenStamp(destSX, destSY, rc) {
  if(!model || !stampOffset) return;
  const rScreen = Math.min(60, getCursorRadius()); // cap brush size for perf
  const opacity = (+stEl.value / 20) * 0.5 + 0.5;  // 0.5–1.0

  const full = compX.getImageData(0, 0, TEX, TEX);
  const src = new Uint8ClampedArray(full.data);
  const dst = full.data;
  const rc2 = rScreen * rScreen;
  const _m = new THREE.Vector2(), _r = new THREE.Raycaster();

  function screenToUV(px, py) {
    if(px < 0 || py < 0 || px > rc.width || py > rc.height) return null;
    _m.x = (px / rc.width) * 2 - 1;
    _m.y = -(py / rc.height) * 2 + 1;
    _r.setFromCamera(_m, camera);
    const hits = _r.intersectObject(model, true);
    if(!hits.length || !hits[0].uv) return null;
    const u = hits[0].uv.x, v = hits[0].uv.y;
    return [
      Math.min(TEX-1, Math.max(0, Math.round(u * TEX))),
      Math.min(TEX-1, Math.max(0, Math.round((uvFlipped ? 1-v : v) * TEX)))
    ];
  }

  // Full per-pixel coverage — raycast every screen pixel in the brush disk
  for(let oy = -rScreen; oy <= rScreen; oy++) {
    for(let ox = -rScreen; ox <= rScreen; ox++) {
      const dd = ox*ox + oy*oy;
      if(dd > rc2) continue;
      const falloff = 1 - Math.sqrt(dd)/rScreen;
      const t = falloff * opacity;
      if(t < 0.02) continue;

      const dPx = destSX + ox, dPy = destSY + oy;
      const sPx = dPx - stampOffset.dx, sPy = dPy - stampOffset.dy;

      const dUV = screenToUV(dPx, dPy); if(!dUV) continue;
      const sUV = screenToUV(sPx, sPy); if(!sUV) continue;

      const di = (dUV[1]*TEX+dUV[0])*4;
      const si = (sUV[1]*TEX+sUV[0])*4;
      dst[di]  = src[di]  *(1-t)+src[si]  *t;
      dst[di+1]= src[di+1]*(1-t)+src[si+1]*t;
      dst[di+2]= src[di+2]*(1-t)+src[si+2]*t;
    }
  }
  compX.putImageData(full, 0, 0);
  if(dynTex) dynTex.needsUpdate = true;
}

// ── Shared world-space brush: projects a sphere onto UV space ──
// mode='blur': box-blurs pixels inside radius
// mode='stamp': copies pixels from srcPoint offset
function applyWorldBrush(hit, mode, srcPoint) {
  if(!model) return;
  model.updateMatrixWorld(true);

  const center = hit.point.clone();
  const worldRadius = (+sEl.value / 100) * (modelRadius * 2) * 0.5;
  if(worldRadius < 0.0001) return;
  const strength = +stEl.value;

  // build a local frame from hit normal
  let nm = new THREE.Vector3();
  if(hit.face) {
    nm.copy(hit.face.normal)
      .applyNormalMatrix(new THREE.Matrix3().getNormalMatrix(hit.object.matrixWorld))
      .normalize();
  } else {
    nm.subVectors(camera.position, center).normalize();
  }

  // For each triangle that intersects the sphere, rasterize brush in UV space
  const full = compX.getImageData(0, 0, TEX, TEX);
  const src  = new Uint8ClampedArray(full.data);
  const dst  = full.data;

  // source world offset for stamp (difference between srcPoint and paintPoint on surface)
  // We'll remap: for each UV pixel we hit, find world-equivalent in source by offset
  // Simpler approach: collect UV pixels that project inside radius,
  // then for blur: box-blur those pixels; for stamp: copy from offset UVs.

  const R2 = worldRadius * worldRadius;
  const kr = Math.max(1, Math.round(strength / 2)); // blur kernel radius

  // Collect a mask of (tx,ty) → weight from world projection
  // We rasterize every polygon in the brush sphere into the texture
  const brushMask = new Float32Array(TEX * TEX); // weight per texel

  const _vv = () => new THREE.Vector3();

  model.traverse(ch => {
    if(!ch.isMesh) return;
    const geo = ch.geometry;
    const pos = geo.attributes.position, uvA = geo.attributes.uv;
    if(!uvA) return;
    const idx = geo.index, tc = idx ? idx.count/3 : pos.count/3, mw = ch.matrixWorld;
    const a=_vv(), b=_vv(), c=_vv();

    for(let t=0; t<tc; t++){
      const i0=idx?idx.getX(t*3):t*3, i1=idx?idx.getX(t*3+1):t*3+1, i2=idx?idx.getX(t*3+2):t*3+2;
      a.fromBufferAttribute(pos,i0).applyMatrix4(mw);
      b.fromBufferAttribute(pos,i1).applyMatrix4(mw);
      c.fromBufferAttribute(pos,i2).applyMatrix4(mw);

      // quick reject: all 3 verts outside sphere
      const da=a.distanceToSquared(center), db=b.distanceToSquared(center), dc=c.distanceToSquared(center);
      if(da>R2*4 && db>R2*4 && dc>R2*4) continue;

      // backface cull
      const e1=_vv().subVectors(b,a), e2=_vv().subVectors(c,a);
      const fn=_vv().crossVectors(e1,e2).normalize();
      if(fn.dot(nm) < 0.05) continue;

      const guv=i=>{const u=uvA.getX(i),v=uvA.getY(i);return[u*TEX,(uvFlipped?1-v:v)*TEX];};
      const [ua,va]=guv(i0),[ub,vb]=guv(i1),[uc,vc]=guv(i2);

      // rasterize this triangle into brushMask with weight = falloff from center
      const PAD=1;
      const mnX=Math.max(0,Math.floor(Math.min(ua,ub,uc))-PAD);
      const mxX=Math.min(TEX-1,Math.ceil(Math.max(ua,ub,uc))+PAD);
      const mnY=Math.max(0,Math.floor(Math.min(va,vb,vc))-PAD);
      const mxY=Math.min(TEX-1,Math.ceil(Math.max(va,vb,vc))+PAD);
      const area=(ub-ua)*(vc-va)-(uc-ua)*(vb-va);
      if(Math.abs(area)<1e-6) continue;
      const inv=1/area;
      const edg=Math.min(.5,1.2*Math.abs(inv)*Math.max(Math.abs(ub-ua)+Math.abs(uc-ua),Math.abs(vb-va)+Math.abs(vc-va)));

      for(let ty=mnY;ty<=mxY;ty++){
        for(let tx=mnX;tx<=mxX;tx++){
          // bary
          const w0=((ub-tx)*(vc-ty)-(uc-tx)*(vb-ty))*inv;
          const w1=((uc-tx)*(va-ty)-(ua-tx)*(vc-ty))*inv;
          const w2=1-w0-w1;
          if(w0<-edg||w1<-edg||w2<-edg) continue;
          const c0=Math.max(0,Math.min(1,w0)),c1=Math.max(0,Math.min(1,w1));
          let c2=1-c0-c1; if(c2<0)c2=0; const s=c0+c1+c2||1;
          // interpolate world position for this texel
          const wx=(c0/s)*a.x+(c1/s)*b.x+(c2/s)*c.x;
          const wy=(c0/s)*a.y+(c1/s)*b.y+(c2/s)*c.y;
          const wz=(c0/s)*a.z+(c1/s)*b.z+(c2/s)*c.z;
          const dx=wx-center.x, dy=wy-center.y, dz=wz-center.z;
          const distSq=dx*dx+dy*dy+dz*dz;
          if(distSq>R2) continue;
          const weight=Math.max(0,1-Math.sqrt(distSq)/worldRadius);
          brushMask[ty*TEX+tx]=Math.max(brushMask[ty*TEX+tx], weight);
        }
      }
    }
  });

  // Now apply the brush operation using the mask
  if(mode==='blur') {
    for(let ty=0;ty<TEX;ty++){
      for(let tx=0;tx<TEX;tx++){
        const w=brushMask[ty*TEX+tx];
        if(w<0.001) continue;
        const t=w*0.8;
        let sr=0,sg=0,sb=0,cnt=0;
        for(let ky=-kr;ky<=kr;ky++) for(let kx=-kr;kx<=kr;kx++){
          const nx=Math.min(TEX-1,Math.max(0,tx+kx)), ny=Math.min(TEX-1,Math.max(0,ty+ky));
          const ni=(ny*TEX+nx)*4;
          sr+=src[ni]; sg+=src[ni+1]; sb+=src[ni+2]; cnt++;
        }
        const i=(ty*TEX+tx)*4;
        dst[i]  =src[i]  *(1-t)+(sr/cnt)*t;
        dst[i+1]=src[i+1]*(1-t)+(sg/cnt)*t;
        dst[i+2]=src[i+2]*(1-t)+(sb/cnt)*t;
      }
    }
  } else if(mode==='stamp') {
    // Fast stamp: project source sphere same way, build srcUV map for painted region
    // Both paint-center and src-center use identical triangle rasterization.
    // For each texel we get its UV in the src projection → copy pixel from there.

    // Build srcUV map: for each texel in brush area, record where to sample from
    // by running the same rasterization centered on srcPoint
    const srcUV = new Int32Array(TEX * TEX * 2).fill(-1); // [tx_src, ty_src] per texel

    model.traverse(ch => {
      if(!ch.isMesh) return;
      const geo=ch.geometry, pos2=geo.attributes.position, uvA=geo.attributes.uv;
      if(!uvA) return;
      const idx=geo.index, tc=idx?idx.count/3:pos2.count/3, mw=ch.matrixWorld;
      const a=_vv(), b=_vv(), c=_vv();

      for(let t=0;t<tc;t++){
        const i0=idx?idx.getX(t*3):t*3, i1=idx?idx.getX(t*3+1):t*3+1, i2=idx?idx.getX(t*3+2):t*3+2;
        a.fromBufferAttribute(pos2,i0).applyMatrix4(mw);
        b.fromBufferAttribute(pos2,i1).applyMatrix4(mw);
        c.fromBufferAttribute(pos2,i2).applyMatrix4(mw);

        // Must be near EITHER paint center OR source center
        const nearPaint = a.distanceToSquared(center)<R2*4 || b.distanceToSquared(center)<R2*4 || c.distanceToSquared(center)<R2*4;
        const nearSrc   = a.distanceToSquared(srcPoint)<R2*4 || b.distanceToSquared(srcPoint)<R2*4 || c.distanceToSquared(srcPoint)<R2*4;
        if(!nearPaint && !nearSrc) continue;

        const [ua,va]=guv2(uvA,i0),[ub,vb]=guv2(uvA,i1),[uc,vc]=guv2(uvA,i2);
        const area=(ub-ua)*(vc-va)-(uc-ua)*(vb-va);
        if(Math.abs(area)<1e-6) continue;
        const inv=1/area;
        const edg=Math.min(.5,1.2*Math.abs(inv)*Math.max(Math.abs(ub-ua)+Math.abs(uc-ua),Math.abs(vb-va)+Math.abs(vc-va)));
        const PAD=1;
        const mnX=Math.max(0,Math.floor(Math.min(ua,ub,uc))-PAD);
        const mxX=Math.min(TEX-1,Math.ceil(Math.max(ua,ub,uc))+PAD);
        const mnY=Math.max(0,Math.floor(Math.min(va,vb,vc))-PAD);
        const mxY=Math.min(TEX-1,Math.ceil(Math.max(va,vb,vc))+PAD);

        for(let ty=mnY;ty<=mxY;ty++){
          for(let tx=mnX;tx<=mxX;tx++){
            const w0=((ub-tx)*(vc-ty)-(uc-tx)*(vb-ty))*inv;
            const w1=((uc-tx)*(va-ty)-(ua-tx)*(vc-ty))*inv;
            const w2=1-w0-w1;
            if(w0<-edg||w1<-edg||w2<-edg) continue;
            const c0=Math.max(0,Math.min(1,w0)),c1=Math.max(0,Math.min(1,w1));
            let c2=1-c0-c1; if(c2<0)c2=0; const s=c0+c1+c2||1;

            // world pos of this texel
            const wx=(c0/s)*a.x+(c1/s)*b.x+(c2/s)*c.x;
            const wy=(c0/s)*a.y+(c1/s)*b.y+(c2/s)*c.y;
            const wz=(c0/s)*a.z+(c1/s)*b.z+(c2/s)*c.z;

            // Is this texel in the PAINT zone? → record it + its source UV
            const dpx=wx-center.x, dpy=wy-center.y, dpz=wz-center.z;
            if(dpx*dpx+dpy*dpy+dpz*dpz <= R2 && brushMask[ty*TEX+tx]>0.001) {
              // find source texel: same triangle but shifted to srcPoint frame
              // source world pos = painted world pos + (srcPoint - center)
              // find where (wx+offX, wy+offY, wz+offZ) maps in UV → already done if
              // that point is in this same triangle
              const swx=wx+srcPoint.x-center.x;
              const swy=wy+srcPoint.y-center.y;
              const swz=wz+srcPoint.z-center.z;
              // project onto triangle plane to get UV
              // Use bary of source world pos in this triangle (if it falls inside)
              const dA = _vv().subVectors({x:b.x,y:b.y,z:b.z}, {x:a.x,y:a.y,z:a.z});
              const dB = _vv().subVectors({x:c.x,y:c.y,z:c.z}, {x:a.x,y:a.y,z:a.z});
              const dP = {x:swx-a.x, y:swy-a.y, z:swz-a.z};
              const d00=dA.dot(dA), d01=dA.dot(dB), d11=dB.dot(dB);
              const d20=dP.x*dA.x+dP.y*dA.y+dP.z*dA.z;
              const d21=dP.x*dB.x+dP.y*dB.y+dP.z*dB.z;
              const denom=d00*d11-d01*d01||1;
              const sv=(d11*d20-d01*d21)/denom;
              const sw=(d00*d21-d01*d20)/denom;
              const su=1-sv-sw;
              // clamp to triangle
              const su2=Math.max(0,Math.min(1,su)), sv2=Math.max(0,Math.min(1,sv));
              let sw2=1-su2-sv2; if(sw2<0)sw2=0; const ss=su2+sv2+sw2||1;
              const stx=Math.round((su2/ss)*ua+(sv2/ss)*ub+(sw2/ss)*uc);
              const sty=Math.round((su2/ss)*va+(sv2/ss)*vb+(sw2/ss)*vc);
              if(stx>=0&&stx<TEX&&sty>=0&&sty<TEX){
                const base=(ty*TEX+tx)*2;
                srcUV[base]=stx; srcUV[base+1]=sty;
              }
            }
          }
        }
      }
    });

    // Apply stamp: copy from srcUV into dst with brush weight
    for(let ty=0;ty<TEX;ty++){
      for(let tx=0;tx<TEX;tx++){
        const w=brushMask[ty*TEX+tx]; if(w<0.001) continue;
        const base=(ty*TEX+tx)*2;
        const stx=srcUV[base], sty=srcUV[base+1];
        if(stx<0) continue;
        const t=w*0.9;
        const si=(sty*TEX+stx)*4, di=(ty*TEX+tx)*4;
        dst[di]  =src[di]  *(1-t)+src[si]  *t;
        dst[di+1]=src[di+1]*(1-t)+src[si+1]*t;
        dst[di+2]=src[di+2]*(1-t)+src[si+2]*t;
      }
    }
  }

  compX.putImageData(full, 0, 0);
  if(dynTex) dynTex.needsUpdate = true;
}

function guv2(uvA,i){const u=uvA.getX(i),v=uvA.getY(i);return[u*TEX,(uvFlipped?1-v:v)*TEX];}

const _v=()=>new THREE.Vector3();

function projectDecal(hit){
  const d=palette[activePal]; if(!d) return;
  model.updateMatrixWorld(true);

  // get mask for this palette item
  const maskIdx=_selMaskForPal[activePal]||0;
  const maskDef=masks[maskIdx];

  const lc=mk(),lx=lc.getContext('2d');
  const pt=hit.point.clone();
  const nm=_v();
  if(hit.face){
    nm.copy(hit.face.normal).applyNormalMatrix(new THREE.Matrix3().getNormalMatrix(hit.object.matrixWorld)).normalize();
  } else nm.subVectors(camera.position,pt).normalize();

  const worldSize=(sEl.value/100)*(modelRadius*2);
  if(worldSize<0.0001){setStatus('Size too small');return;}

  // Aspect-correct projector — preserves decal image proportions
  const aspect = d.img.width / d.img.height;
  const worldW = worldSize * (aspect >= 1 ? 1 : aspect);   // width in world units
  const worldH = worldSize * (aspect >= 1 ? 1/aspect : 1); // height in world units
  const halfW = worldW/2, halfH = worldH/2;

  const angle=rEl.value*Math.PI/180;
  let up=Math.abs(nm.y)>.95?_v().set(1,0,0):_v().set(0,1,0);
  const right=_v().crossVectors(up,nm).normalize();
  up=_v().crossVectors(nm,right).normalize();
  const cA=Math.cos(angle),sA=Math.sin(angle);
  const rR=_v().addScaledVector(right,cA).addScaledVector(up,sA);
  const uR=_v().addScaledVector(right,-sA).addScaledVector(up,cA);

  // prepare decal pixels
  const dc=Object.assign(document.createElement('canvas'),{width:d.img.width,height:d.img.height});
  dc.getContext('2d').drawImage(d.img,0,0);
  let dd=dc.getContext('2d').getImageData(0,0,dc.width,dc.height);

  // apply mask to decal alpha
  if(maskDef.img){
    const mc=Object.assign(document.createElement('canvas'),{width:d.img.width,height:d.img.height});
    mc.getContext('2d').drawImage(maskDef.img,0,0,d.img.width,d.img.height);
    const md_=mc.getContext('2d').getImageData(0,0,d.img.width,d.img.height);
    for(let i=0;i<dd.data.length;i+=4){
      // mask brightness (R channel, greyscale) modulates alpha
      const mb=md_.data[i]/255;
      dd.data[i+3]=Math.round(dd.data[i+3]*mb);
    }
  }
  const ddata=dd.data;

  const li=lx.createImageData(TEX,TEX),buf=li.data;
  let painted=0;

  model.traverse(ch=>{
    if(!ch.isMesh) return;
    const geo=ch.geometry,pos=geo.attributes.position,uvA=geo.attributes.uv;
    if(!uvA) return;
    const idx=geo.index,tc=idx?idx.count/3:pos.count/3,mw=ch.matrixWorld;
    const a=_v(),b=_v(),c=_v();
    for(let t=0;t<tc;t++){
      const i0=idx?idx.getX(t*3):t*3,i1=idx?idx.getX(t*3+1):t*3+1,i2=idx?idx.getX(t*3+2):t*3+2;
      a.fromBufferAttribute(pos,i0).applyMatrix4(mw);
      b.fromBufferAttribute(pos,i1).applyMatrix4(mw);
      c.fromBufferAttribute(pos,i2).applyMatrix4(mw);
      const prj=p=>{const r=_v().subVectors(p,pt);return{x:r.dot(rR),y:r.dot(uR),z:r.dot(nm)};};
      const pa=prj(a),pb=prj(b),pc=prj(c);
      const depth=Math.max(worldW,worldH);
      if((pa.x<-halfW&&pb.x<-halfW&&pc.x<-halfW)||(pa.x>halfW&&pb.x>halfW&&pc.x>halfW)||
         (pa.y<-halfH&&pb.y<-halfH&&pc.y<-halfH)||(pa.y>halfH&&pb.y>halfH&&pc.y>halfH)||
         (pa.z<-depth&&pb.z<-depth&&pc.z<-depth)||(pa.z>depth&&pb.z>depth&&pc.z>depth)) continue;
      const e1=_v().subVectors(b,a),e2=_v().subVectors(c,a);
      if(_v().crossVectors(e1,e2).normalize().dot(nm)<.05) continue;
      const guv=i=>{const u=uvA.getX(i),v=uvA.getY(i);return[u*TEX,(uvFlipped?1-v:v)*TEX];};
      const [ua,va]=guv(i0),[ub,vb]=guv(i1),[uc,vc]=guv(i2);
      // project into decal UV: x/worldW → 0..1 along width, y/worldH → 0..1 along height
      const dco=p=>[(p.x/worldW)+.5, .5-(p.y/worldH)];
      const [a0,a1]=dco(pa),[b0,b1]=dco(pb),[c0,c1]=dco(pc);
      rasterTri(buf,ua,va,ub,vb,uc,vc,a0,a1,b0,b1,c0,c1,ddata,dc.width,dc.height,1);
      painted++;
    }
  });

  if(!painted){setStatus('Decal missed polygons — increase size');return;}
  dilate(buf,TEX,TEX,2);

  // Paint onto selected layer (or create new if none selected)
  let targetLayer;
  if(selLayer >= 0 && selLayer < layers.length) {
    targetLayer = layers[selLayer];
    // composite the new stroke onto the existing layer canvas
    const tctx = targetLayer.canvas.getContext('2d');
    lx.putImageData(li,0,0);
    tctx.drawImage(lc,0,0);
    // update thumb
    const th=Object.assign(document.createElement('canvas'),{width:48,height:48});
    th.getContext('2d').drawImage(targetLayer.canvas,0,0,48,48);
    targetLayer.thumb = th.toDataURL();
    pushUndo({type:'stroke', id:targetLayer.id});
  } else {
    lx.putImageData(li,0,0);
    const th=Object.assign(document.createElement('canvas'),{width:48,height:48});
    th.getContext('2d').drawImage(lc,0,0,48,48);
    targetLayer = {id:++seq,name:`#${seq} ${d.name}`,canvas:lc,thumb:th.toDataURL(),
                    visible:true,open:false,opacity:100,brightness:100,contrast:100};
    layers.push(targetLayer);
    selLayer=layers.length-1;
    pushUndo({type:'add',id:targetLayer.id});
  }
  recomp(); renderLayers();
  const mname=maskDef.img?` [mask: ${maskDef.name}]`:'';
  setStatus(`Decal painted — ${painted} polygons${mname}`);
}

function rasterTri(buf,x0,y0,x1,y1,x2,y2,u0,v0,u1,v1,u2,v2,src,sw,sh,ga){
  const PAD=1;
  const mnX=Math.max(0,Math.floor(Math.min(x0,x1,x2))-PAD);
  const mxX=Math.min(TEX-1,Math.ceil(Math.max(x0,x1,x2))+PAD);
  const mnY=Math.max(0,Math.floor(Math.min(y0,y1,y2))-PAD);
  const mxY=Math.min(TEX-1,Math.ceil(Math.max(y0,y1,y2))+PAD);
  if(mxX<mnX||mxY<mnY) return;
  const area=(x1-x0)*(y2-y0)-(x2-x0)*(y1-y0);
  if(Math.abs(area)<1e-6) return;
  const inv=1/area;
  const edg=Math.min(.5,1.2*Math.abs(inv)*Math.max(Math.abs(x1-x0)+Math.abs(x2-x0),Math.abs(y1-y0)+Math.abs(y2-y0)));
  for(let y=mnY;y<=mxY;y++){
    for(let x=mnX;x<=mxX;x++){
      const w0=((x1-x)*(y2-y)-(x2-x)*(y1-y))*inv;
      const w1=((x2-x)*(y0-y)-(x0-x)*(y2-y))*inv;
      const w2=1-w0-w1;
      if(w0<-edg||w1<-edg||w2<-edg) continue;
      const c0=Math.max(0,Math.min(1,w0)),c1=Math.max(0,Math.min(1,w1));
      let c2=1-c0-c1;if(c2<0)c2=0;
      const s=c0+c1+c2||1;
      const du=(c0/s)*u0+(c1/s)*u1+(c2/s)*u2;
      const dv=(c0/s)*v0+(c1/s)*v1+(c2/s)*v2;
      if(du<-.01||du>1.01||dv<-.01||dv>1.01) continue;
      const sx=Math.min(sw-1,Math.max(0,du*sw|0)),sy=Math.min(sh-1,Math.max(0,dv*sh|0));
      const si=(sy*sw+sx)*4;
      const sa=(src[si+3]/255)*ga;if(sa<.003) continue;
      const di=(y*TEX+x)*4;
      buf[di]=src[si];buf[di+1]=src[si+1];buf[di+2]=src[si+2];
      buf[di+3]=Math.max(buf[di+3],sa*255|0);
    }
  }
}

function dilate(buf,w,h,n){
  for(let it=0;it<n;it++){
    const cp=new Uint8ClampedArray(buf);
    for(let y=1;y<h-1;y++) for(let x=1;x<w-1;x++){
      const i=(y*w+x)*4;if(cp[i+3]>8) continue;
      let bi=-1,ba=0;
      for(let dy=-1;dy<=1;dy++) for(let dx=-1;dx<=1;dx++){
        if(!dx&&!dy) continue;
        const j=((y+dy)*w+(x+dx))*4;
        if(cp[j+3]>ba){ba=cp[j+3];bi=j;}
      }
      if(bi>=0&&ba>8){buf[i]=cp[bi];buf[i+1]=cp[bi+1];buf[i+2]=cp[bi+2];buf[i+3]=ba;}
    }
  }
}

// ── Undo/Redo ──
function applyUndo(a){
  if(a.type==='add'){const p=layers.findIndex(l=>l.id===a.id);if(p>=0){a.layer=layers[p];a.pos=p;layers.splice(p,1);}}
  else if(a.type==='del'){layers.splice(Math.min(a.pos,layers.length),0,a.layer);}
  else if(a.type==='vis'){const L=layers.find(l=>l.id===a.id);if(L)L.visible=!L.visible;}
}
function applyRedo(a){
  if(a.type==='add'){layers.splice(Math.min(a.pos,layers.length),0,a.layer);}
  else if(a.type==='del'){const p=layers.findIndex(l=>l.id===a.layer.id);if(p>=0)layers.splice(p,1);}
  else if(a.type==='vis'){const L=layers.find(l=>l.id===a.id);if(L)L.visible=!L.visible;}
}
function doUndo(){const a=undoStack.pop();if(!a)return;applyUndo(a);redoStack.push(a);selLayer=-1;recomp();renderLayers();refreshHist();setStatus('Undone');}
function doRedo(){const a=redoStack.pop();if(!a)return;applyRedo(a);undoStack.push(a);selLayer=-1;recomp();renderLayers();refreshHist();setStatus('Redone');}
document.getElementById('undoBtn').addEventListener('click',doUndo);
document.getElementById('redoBtn').addEventListener('click',doRedo);
window.addEventListener('keydown',e=>{
  // Don't intercept when typing in an input/textarea
  if(e.target.tagName==='INPUT'||e.target.tagName==='TEXTAREA') return;
  if(!(e.ctrlKey||e.metaKey)) return;
  if(e.key==='z'&&!e.shiftKey){e.preventDefault();doUndo();}
  if(e.key==='y'||(e.key==='z'&&e.shiftKey)){e.preventDefault();doRedo();}
});

// ── Export ──
document.getElementById('exportBtn').addEventListener('click',()=>{
  const out=Object.assign(document.createElement('canvas'),{width:TEX,height:TEX});
  const ox=out.getContext('2d');
  // Canvas stores pixels with V flipped vs standard UV (0=top in canvas, 0=bottom in UV).
  // Always flip vertically on export so the file matches the original UV convention.
  ox.translate(0,TEX);
  ox.scale(1,-1);
  ox.drawImage(compC,0,0);
  out.toBlob(blob=>{
    const a=document.createElement('a');
    a.href=URL.createObjectURL(blob);
    a.download='decal_texture.png';
    a.click();
    setStatus('Exported — decal_texture.png');
  },'image/png');
});

// init mask list
renderMasks();

// ── Load image as new layer ──
document.getElementById('loadImgLayerBtn').addEventListener('click',()=>document.getElementById('layerImgIn').click());
document.getElementById('layerImgIn').addEventListener('change',e=>{
  const f=e.target.files[0]; if(!f) return;
  const img=new Image();
  const objUrl=URL.createObjectURL(f);
  e.target.value='';
  img.onload=()=>{
    const lc=mk();
    lc.getContext('2d').drawImage(img,0,0,TEX,TEX);
    const th=Object.assign(document.createElement('canvas'),{width:48,height:48});
    th.getContext('2d').drawImage(lc,0,0,48,48);
    const layer={id:++seq,name:f.name,canvas:lc,thumb:th.toDataURL(),
                  visible:true,open:false,opacity:100,brightness:100,contrast:100};
    layers.push(layer);
    selLayer=layers.length-1;
    recomp(); renderLayers();
    pushUndo({type:'add',id:layer.id});
    setStatus(`Image layer added: ${f.name}`);
    URL.revokeObjectURL(objUrl);
  };
  img.src=objUrl;
});
document.getElementById('addLayerBtn').addEventListener('click', () => {
  const lc = mk(), lx = lc.getContext('2d');
  // blank transparent layer
  const th = Object.assign(document.createElement('canvas'),{width:48,height:48});
  // thumb shows a checkerboard to indicate transparency
  const tx = th.getContext('2d');
  tx.fillStyle='#555'; tx.fillRect(0,0,48,48);
  tx.fillStyle='#777'; for(let y=0;y<48;y+=8) for(let x=0;x<48;x+=8) if((x+y)%16===0) tx.fillRect(x,y,8,8);
  const layer = {id:++seq,name:`Layer ${seq}`,canvas:lc,thumb:th.toDataURL(),
                  visible:true,open:false,opacity:100,brightness:100,contrast:100};
  layers.push(layer);
  selLayer = layers.length-1;
  recomp(); renderLayers();
  pushUndo({type:'add',id:layer.id});
  setStatus(`Layer ${seq} added — paint decals onto it`);
});

document.getElementById('dupLayerBtn').addEventListener('click', () => {
  if(selLayer < 0 || selLayer >= layers.length) return;
  const src = layers[selLayer];
  const lc = mk();
  lc.getContext('2d').drawImage(src.canvas, 0, 0);
  const th = Object.assign(document.createElement('canvas'),{width:48,height:48});
  th.getContext('2d').drawImage(src.canvas, 0, 0, 48, 48);
  const layer = {id:++seq, name:`${src.name} copy`, canvas:lc, thumb:th.toDataURL(),
                  visible:true, open:false, opacity:src.opacity, brightness:src.brightness, contrast:src.contrast};
  layers.splice(selLayer+1, 0, layer);
  selLayer = selLayer+1;
  recomp(); renderLayers();
  pushUndo({type:'add', id:layer.id});
  setStatus(`Duplicated: ${layer.name}`);
});
